<?php
namespace App\Models;use App\Models\Concerns\HasMediaAssets;use Illuminate\Database\Eloquent\Factories\HasFactory;use Illuminate\Database\Eloquent\Model;
class Shop extends Model{use HasFactory,HasMediaAssets;protected $guarded=[];protected $casts=['buys_items'=>'boolean','purchase_rate_basis_points'=>'integer','starts_at'=>'immutable_datetime','ends_at'=>'immutable_datetime','sort_order'=>'integer'];public function npc(){return$this->belongsTo(Npc::class);}public function locations(){return$this->hasMany(ShopLocation::class);}public function offers(){return$this->hasMany(ShopOffer::class);}public function purchases(){return$this->hasMany(ShopPurchase::class);}}
